const input = $input.first().json;

// ── Validate required fields ──
if (!input) {
  throw new Error('No input data received');
}

// ── Core scenario logic ──
// Scenario: Typeform complete → Pipedrive deal → assign to sales rep
const output = {
  ...input,
  processed: true,
  processedAt: new Date().toISOString(),
  domain: 'lead-capture',
  scenario: 'Typeform complete → Pipedrive deal → assign to sales rep',
  gridhandVersion: '1.0',
};

return [{ json: output }];

